import android.content.Context;
import android.os.AsyncTask;
import android.util.Log;
import okhttp3.OkHttpClient;
import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class UserDataFetcher {
    private static final String TAG = "UserDataFetcher";

    public interface OnUserDataFetchedListener {
        void onUserDataFetched(List<User> users);
    }

    private OkHttpClient client;
    private Retrofit retrofit;
    private UserService userService;

    public UserDataFetcher(Context context) {
        this.client = new OkHttpClient();
        this.retrofit = new Retrofit.Builder()
                .baseUrl("https://api.example.com/users")
                .addConverterFactory(GsonConverterFactory.create())
                .build();
        this.userService = retrofit.create(UserService.class);
    }

    public void fetchUserData(OnUserDataFetchedListener listener) {
        Call<List<User>> call = userService.getUsers();
        call.enqueue(new Callback<List<User>>() {
            @Override
            public void onResponse(Call<List<User>> call, Response<List<User>> response) {
                if (response.isSuccessful()) {
                    List<User> users = response.body();
                    listener.onUserDataFetched(users);
                } else {
                    Log.e(TAG, "Failed to fetch user data: " + response.errorBody());
                }
            }

            @Override
            public void onFailure(Call<List<User>> call, Throwable t) {
                Log.e(TAG, "Failed to fetch user data: " + t.getMessage());
            }
        });
    }
}